<div class="form-group"><label>Cliente</label><select class="form-control" name="clientesid" id="edit_clientesid"><?php foreach ($clientes as $cl): ?><option value="<?= $cl->clientesid; ?>"><?= $cl->nome; ?></option><?php endforeach; ?></select></div>
<div class="row"><div class="col-md-6"><div class="form-group"><label>Regime</label><select class="form-control" name="regime_tributario" id="edit_regime_tributario"><option value="SIMPLES_NACIONAL">Simples Nacional</option><option value="MEI">MEI</option><option value="LUCRO_PRESUMIDO">Lucro Presumido</option><option value="LUCRO_REAL">Lucro Real</option></select></div></div><div class="col-md-6"><div class="form-group"><label>CNAE</label><input type="text" class="form-control" name="cnae" id="edit_cnae"></div></div></div>
<div class="row"><div class="col-md-6"><div class="form-group"><label>Insc. Estadual</label><input type="text" class="form-control" name="inscricao_estadual" id="edit_inscricao_estadual"></div></div><div class="col-md-6"><div class="form-group"><label>Insc. Municipal</label><input type="text" class="form-control" name="inscricao_municipal" id="edit_inscricao_municipal"></div></div></div>
<div class="row"><div class="col-md-6"><div class="form-group"><label>Aliq. ISS</label><input type="number" step="0.01" class="form-control" name="aliquota_iss" id="edit_aliquota_iss"></div></div><div class="col-md-6"><div class="form-group"><label>Aliq. ICMS</label><input type="number" step="0.01" class="form-control" name="aliquota_icms" id="edit_aliquota_icms"></div></div></div>
