</div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-dismiss="modal">Cancelar</button><button type="submit" class="btn btn-primary">Atualizar</button></div></form></div></div></div>

<script>
$(document).ready(function() {
    if (!$.fn.DataTable.isDataTable('#tbl_fiscal')) $('#tbl_fiscal').DataTable({ "info": true, "searching": true, "paging": true, "pageLength": 15, "order": [[0, 'asc']], "language": { "url": "//cdn.datatables.net/plug-ins/9dcbecd42ad/i18n/Portuguese.json" } });
    $('.btn-edit').on('click', function() {
        $.getJSON('<?= base_url(); ?>cadastrofiscal/get/' + $(this).data('id'), function(data) {
            $('#edit_id').val(data.idcadastro); $('#edit_clientesid').val(data.clientesid);
            $('#edit_regime_tributario').val(data.regime_tributario); $('#edit_cnae').val(data.cnae);
            $('#edit_inscricao_estadual').val(data.inscricao_estadual); $('#edit_inscricao_municipal').val(data.inscricao_municipal);
            $('#edit_aliquota_iss').val(data.aliquota_iss); $('#edit_aliquota_icms').val(data.aliquota_icms);
            $('#edit_observacoes').val(data.observacoes);
            $('#modalEdit').modal('show');
        });
    });
});
</script>
